1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteResult {
13	  premium: number;
14	}
15	
16	const PROCESSING_FEE = 5;
17	const BASE_PREMIUMS: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	  rune: 25,
23	};
24	const FIRST_INSURANCE_SURCHARGE = 0.1;
25	
26	// Rounds up in MHPCO's favor, guarding against floating-point drift
27	// (e.g. 197.50000000001 should round to 198, not be inflated by noise).
28	const roundUpInFavor = (amount: number): number =>
29	  Math.ceil(Number(amount.toFixed(6)));
30	
31	const itemPremium = (item: Item): number => {
32	  const basePremium = BASE_PREMIUMS[item.type];
33	  return basePremium * (1 + FIRST_INSURANCE_SURCHARGE);
34	};
35	
36	export const quote = (customer: Customer, items: Item[]): QuoteResult => {
37	  const basePremiumTotal = items.reduce(
38	    (total, item) => total + itemPremium(item),
39	    0,
40	  );
41	  const exactPremium = basePremiumTotal + PROCESSING_FEE;
42	  return { premium: roundUpInFavor(exactPremium) };
43	};
44	
45	export const claim = (...args: unknown[]): unknown => {
46	  return undefined;
47	};
